1	<script lang="ts">
2		import { createClient } from '$lib/gql/client';
3		import { invalidateAll } from '$app/navigation';
4		import { onMount } from 'svelte';
5		import type { PageData } from './$types';
6		import { SESSION_DETAIL_QUERY, SESSION_EXECUTION_QUERY, type SessionNode } from './+page';
7	
8		let { data }: { data: PageData } = $props();
9	
10		// Track which sessions are expanded
11		let expanded = $state<Set<string>>(new Set());
12		let sessionBodies = $state<Record<string, Pick<SessionNode, 'prompt' | 'response' | 'stderr'>>>(
13			{}
14		);
15		let sessionExecutions = $state<Record<string, string | null>>({});
16	
17		function executionHref(executionId: string): string {
18			return `/nodes/${data.nodeId}/projects/${data.projectId}/executions/${executionId}`;
19		}
20	
21		onMount(() => {
22			const timer = window.setInterval(() => {
23				void invalidateAll();
24			}, 2000);
25			return () => window.clearInterval(timer);
26		});
27	
28		async function toggle(id: string) {
29			const next = new Set(expanded);
30			if (next.has(id)) {
31				next.delete(id);
32			} else {
33				next.add(id);
34				if (!sessionBodies[id]) {
35					const client = createClient(fetch);
36					const detail = await client.request<{ agentSession: SessionNode | null }>(
37						SESSION_DETAIL_QUERY,
38						{ id }
39					);
40					if (detail.agentSession) {
41						sessionBodies = {
42							...sessionBodies,
43							[id]: {
44								prompt: detail.agentSession.prompt,
45								response: detail.agentSession.response,
46								stderr: detail.agentSession.stderr
47							}
48						};
49					}
50				}
51				if (sessionExecutions[id] === undefined) {
52					try {
53						const client2 = createClient(fetch);
54						const exec = await client2.request<{ executionBySessionId: { id: string } | null }>(
55							SESSION_EXECUTION_QUERY,
56							{ projectID: data.projectId, sessionID: id }
57						);
58						sessionExecutions = {
59							...sessionExecutions,
60							[id]: exec.executionBySessionId?.id ?? null
61						};
62					} catch {
63						sessionExecutions = { ...sessionExecutions, [id]: null };
64					}
65				}
66			}
67			expanded = next;
68		}
69	
70		const recordingGap = $derived.by(() => {
71			const sorted = [...data.sessions.edges].sort(
72				(a, b) => new Date(a.node.startedAt).getTime() - new Date(b.node.startedAt).getTime()
73			);
74			for (let i = 1; i < sorted.length; i++) {
75				const prev = new Date(sorted[i - 1].node.startedAt);
76				const next = new Date(sorted[i].node.startedAt);
77				if (next.getTime() - prev.getTime() > 24 * 60 * 60 * 1000) {
78					return `No sessions recorded between ${prev.toLocaleDateString()} and ${next.toLocaleDateString()}`;
79				}
80			}
81			return null;
82		});
83	
84		// Aggregate token summary
85		const summary = $derived.by(() => {
86			let totalPrompt = 0;
87			let totalCompletion = 0;
88			let totalCached = 0;
89			let totalTokens = 0;
90			let paidSessions = 0;
91			let subscriptionSessions = 0;
92			for (const edge of data.sessions.edges) {
93				const s = edge.node;
94				if (s.billingMode === 'paid') paidSessions++;
95				if (s.billingMode === 'subscription') subscriptionSessions++;
96				if (s.tokens) {
97					totalPrompt += s.tokens.prompt ?? 0;
98					totalCompletion += s.tokens.completion ?? 0;
99					totalCached += s.tokens.cached ?? 0;
100					totalTokens += s.tokens.total ?? 0;
101				}
102			}
103			const cacheRate = totalTokens > 0 ? Math.round((totalCached / totalTokens) * 100) : 0;
104			return {
105				totalPrompt,
106				totalCompletion,
107				totalCached,
108				totalTokens,
109				cacheRate,
110				paidSessions,
111				subscriptionSessions
112			};
113		});
114	
115		function fmtDuration(ms: number): string {
116			if (ms < 1000) return `${ms}ms`;
117			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
118			const m = Math.floor(ms / 60_000);
119			const s = Math.floor((ms % 60_000) / 1000);
120			return `${m}m ${s}s`;
121		}
122	
123		function fmtDate(iso: string): string {
124			return new Date(iso).toLocaleString();
125		}
126	
127		function fmtCost(c: number | null): string {
128			if (c == null) return '—';
129			return `$${c.toFixed(4)}`;
130		}
131	
132		function fmtCardCost(value: number, hasSessions: boolean): string {
133			if (!hasSessions) return '—';
134			return `$${value.toFixed(2)}`;
135		}
136	
137		function fmtLocalValue(): string {
138			if (data.costSummary.localSessionCount === 0) return '0';
139			if (data.costSummary.localEstimatedUsd != null) {
140				return `$${data.costSummary.localEstimatedUsd.toFixed(2)} est.`;
141			}
142			return data.costSummary.localSessionCount.toLocaleString();
143		}
144	
145		function billingBadge(mode: SessionNode['billingMode']): string {
146			switch (mode) {
147				case 'paid':
148					return 'cash';
149				case 'subscription':
150					return 'sub';
151				case 'local':
152					return 'local';
153				default:
154					return mode;
155			}
156		}
157	
158		function billingDescription(mode: SessionNode['billingMode']): string {
159			switch (mode) {
160				case 'paid':
161					return 'Billed by pay-per-token APIs (OpenRouter, direct API keys)';
162				case 'subscription':
163					return 'Dollar-equivalent for tokens consumed under Claude Code / Codex subscriptions. Not cash out of pocket.';
164				case 'local':
165					return 'Sessions served locally. Compute cost not modeled.';
166				default:
167					return 'Cost bucket is unknown.';
168			}
169		}
170	
171		function billingBadgeClass(mode: SessionNode['billingMode']): string {
172			switch (mode) {
173				case 'paid':
174					return 'badge-billing-paid';
175				case 'subscription':
176					return 'badge-billing-subscription';
177				case 'local':
178					return 'badge-billing-local';
179				default:
180					return 'badge-billing-local';
181			}
182		}
183	
184		function statusBadgeClass(status: string): string {
185			switch (status) {
186				case 'completed':
187					return 'badge-status-completed';
