14			seq: number;
15			ts: string | null;
16			inputs: string | null;
17			output: string | null;
18			truncated: boolean | null;
19		}
20		interface ToolCallEdge {
21			node: ToolCall;
22			cursor: string;
23		}
24		interface ToolCallConnection {
25			edges: ToolCallEdge[];
26			pageInfo: { hasNextPage: boolean; endCursor: string | null };
27			totalCount: number;
28		}
29	
30		let toolCalls = $state<ToolCall[]>([]);
31		let toolCallsLoaded = $state(false);
32		let toolCallsLoading = $state(false);
33		let toolCallsTotal = $state(0);
34		let toolCallsCursor = $state<string | null>(null);
35		let toolCallsHasMore = $state(false);
36		let expanded = $state<Set<number>>(new Set());
37	
38		interface SessionDetail {
39			id: string;
40			harness: string;
41			model: string;
42			cost: number | null;
43			billingMode: string;
44			tokens: { prompt: number | null; completion: number | null; total: number | null; cached: number | null } | null;
45			status: string;
46			outcome: string | null;
47		}
48		let sessionDetail = $state<SessionDetail | null>(null);
49		let sessionLoaded = $state(false);
50		let sessionLoading = $state(false);
51	
52		async function loadToolCalls(more = false) {
53			if (toolCallsLoading) return;
54			toolCallsLoading = true;
55			try {
56				const client = createClient(fetch);
57				const result = await client.request<{ executionToolCalls: ToolCallConnection }>(
58					TOOL_CALLS_QUERY,
59					{ id: data.executionId, first: 50, after: more ? toolCallsCursor : null }
60				);
61				const conn = result.executionToolCalls;
62				const newCalls = conn.edges.map((e) => e.node);
63				toolCalls = more ? [...toolCalls, ...newCalls] : newCalls;
64				toolCallsTotal = conn.totalCount;
65				toolCallsCursor = conn.pageInfo.endCursor;
66				toolCallsHasMore = conn.pageInfo.hasNextPage;
67				toolCallsLoaded = true;
68			} finally {
69				toolCallsLoading = false;
70			}
71		}
72	
73		async function loadSession() {
74			if (!data.execution?.sessionId || sessionLoading || sessionLoaded) return;
75			sessionLoading = true;
76			try {
77				const client = createClient(fetch);
78				const result = await client.request<{ agentSession: SessionDetail | null }>(
79					SESSION_QUERY,
80					{ id: data.execution.sessionId }
81				);
82				sessionDetail = result.agentSession;
83				sessionLoaded = true;
84			} finally {
85				sessionLoading = false;
86			}
87		}
88	
89		function pickTab(tab: Tab) {
90			activeTab = tab;
91			if (tab === 'tools' && !toolCallsLoaded) {
